mapper.select:


        SELECT A.USER_ID, A.USER_NM, A.CST_ID, A.CST_NM, A.USER_TP_CD, A.USER_REF_ID, A.EMAIL, A.TEL_NO,
		        A.MPHONE_NO, A.FAX_NO, A.CST_TP_CD, A.USER_POSIT_NM, A.USER_DEPT_NM, A.USER_DEPT_NM_VIEW, A.STATUS, A.RGSTR_DT, 
                A.RGSTR_NM, A.RGSTR_ID, A.MDFR_DT, A.MDFR_NM, A.MDFR_ID, A.CONSULT_CNT,
                A.NOTICE1_YN, A.NOTICE2_YN, A.NOTICE3_YN, A.NOTICE4_YN
        FROM (

        SELECT USER_ID, USER_NM, CST_ID, CST_NM, USER_TP_CD, USER_REF_ID, EMAIL, TEL_NO,
                        MPHONE_NO, FAX_NO, CST_TP_CD, USER_POSIT_NM, USER_DEPT_NM, ISNULL([dbo].FN_FS_GETSNAME1('9',USER_REF_ID), '') AS USER_DEPT_NM_VIEW , STATUS, RGSTR_DT, 
                        [dbo].FN_FS_GETSNAME1('1',RGSTR_ID) as RGSTR_NM, RGSTR_ID, MDFR_DT, [dbo].FN_FS_GETSNAME1('1',MDFR_ID) as MDFR_NM, MDFR_ID,
                        (SELECT ISNULL(COUNT(FS_CHAT_ID),0) FROM TB_FS_DTL_MEM B WHERE FS_CHAT_ID = USER_ID  AND FS_CHAT_YN = 'Y') AS CONSULT_CNT,
                        NOTICE1_YN, NOTICE2_YN, NOTICE3_YN, NOTICE4_YN

        FROM [CESCOFS].[dbo].[TB_FS_USER]
        ) as A



                WHERE A.CONSULT_CNT = 0





                WHERE A.CONSULT_CNT >= #{consult_cnt}





            AND A.CST_ID = #{cst_id}




            AND A.USER_NM LIKE '%' + #{user_nm} + '%' 




            AND A.USER_ID LIKE '%' + #{user_id} + '%' 




            AND A.RGSTR_DT >= #{start_date}




            AND A.RGSTR_DT <= #{end_date}




            AND A.CST_TP_CD = #{cst_tp_cd}




            AND A.STATUS = #{status}



            ORDER BY RGSTR_DT DESC
